mapper.select:
select IFNULL(sum(apply_refund_num), 0) as apply_refund_num from `eb_refund_order_info`
where refund_order_no in (SELECT refund_order_no FROM `eb_refund_order` where refund_status = 3 and date_format(refund_time, '%Y-%m-%d') = #{date})
  and product_id = #{proId}

select IFNULL(sum(apply_refund_num), 0) as apply_refund_num from `eb_refund_order_info`
where refund_order_no in (SELECT refund_order_no FROM `eb_refund_order` where refund_status = 3 and date_format(refund_time, '%Y-%m-%d') = #{date})
  and mer_id = #{merId}
